/**
 * @summary Send a proctor message
 */
export const getSendProctorMessageUrl = () => {
  return `/api/proctor-messages`;
};

export const sendProctorMessage = async (
  sendProctorMessageBody: SendProctorMessageBody,
  options?: RequestInit,
): Promise<ProctorMessage> => {
  return customFetch<ProctorMessage>(getSendProctorMessageUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(sendProctorMessageBody),
  });
};

export const getSendProctorMessageMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendProctorMessage>>,
    TError,
    { data: BodyType<SendProctorMessageBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof sendProctorMessage>>,
  TError,
  { data: BodyType<SendProctorMessageBody> },
  TContext
> => {
  const mutationKey = ["sendProctorMessage"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof sendProctorMessage>>,
    { data: BodyType<SendProctorMessageBody> }
  > = (props) => {
    const { data } = props ?? {};

    return sendProctorMessage(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

